24	
25	namespace cxx {
26	
27	void map::Init() {
28	    uint32_t cap = 64 / CoreApi::Bits();
29	    __cxx_map_offset__ = {
30	        .__begin_node_ = 0,
31	        .__pair1_ = 8 / cap,
32	        .__pair3_ = 16 / cap,
33	    };
34	
35	    __cxx_map_size__ = {
36	        .THIS = 24 / cap,
37	    };
38	}
39	
40	void map::pair::Init() {
41	    uint32_t cap = 64 / CoreApi::Bits();
42	    __cxx_map_pair_offset__ = {
43	        .__left_ = 0,
44	        .__right_ = 8 / cap,
45	        .__parent_ = 16 / cap,
46	        .__color_ = 24 / cap,
47	        .__data_ = 32 / cap,
48	    };
49	
50	    __cxx_map_pair_size__ = {
51	        .THIS = 32 / cap,
52	    };
53	}
54	
55	map::iterator map::begin() {
56	    map::iterator it(this, 0);
57	    if (!cache.size() && size()) {
58	        map::pair __pair1_ = __pair1();
59	        it.traversal(__pair1_);
60	    }
61	    return it;
62	}
63	
64	map::iterator map::end() {
65	    map::iterator it(this, size());
66	    return it;
67	}
68	
69	uint64_t map::size() {
70	    return __pair3();
71	}
72	
73	void map::iterator::traversal(pair& p) {
74	    if (p.__left()) {
75	        map::pair left(p.__left(), p);
76	        traversal(left);
77	    }
78	
79	    if (p.__right()) {
80	        map::pair right(p.__right(), p);
81	        traversal(right);
82	    }
83	
84	    __map_->cache.push_back(p);
85	}
86	
87	map::iterator& map::iterator::operator++() {
88	    current++;
89	    return *this;
90	}
91	
92	bool map::iterator::operator==(iterator other) const {
93	    return current == other.current;
94	}
95	
96	bool map::iterator::operator!=(iterator other) const {
97	    return current != other.current;
98	}
99	
100	uint64_t map::iterator::operator*() {
101	    pair& p1 = __map_->cache[current];
102	    return p1.__data();
103	}
104	
105	} // namespace cxx
